import requests
import geopandas as gpd
import pandas as pd
from shapely.geometry import Point
import warnings; warnings.filterwarnings('ignore')

def download_data():
    global result
    # Overpass API — faster than OSMnx for POIs
    overpass_url = 'https://overpass-api.de/api/interpreter'
    overpass_query = '''
    [out:json][timeout:60];
    area["name"="{city_name}"]->.searchArea;
    (
      nwr[amenity~"hospital|clinic|doctors"](area.searchArea);
    );
    out center;
    '''
    response = requests.get(overpass_url, params={'data': overpass_query}, timeout=60)
    data = response.json()
    rows = []
    for el in data.get('elements', []):
        lat = el.get('lat') or el.get('center', {}).get('lat')
        lon = el.get('lon') or el.get('center', {}).get('lon')
        if lat and lon:
            rows.append({'amenity': el.get('tags', {}).get('amenity', 'hospital'), 'name': el.get('tags', {}).get('name', ''), 'geometry': Point(lon, lat)})
    result = gpd.GeoDataFrame(rows, crs='EPSG:4326') if rows else gpd.GeoDataFrame(columns=['amenity','name','geometry'], geometry='geometry', crs='EPSG:4326')

download_data()

